class User:
    def __init__(self, username, user_tier, is_admin):
        self.username = username
        self.user_tier = user_tier
        self.is_admin = is_admin


class Item:
    def __init__(self, name, price):
        self.name = name
        self.price = price


class Cart:
    def __init__(self, user, items):
        self.user = user
        self.items = items


class DiscountCode:
    def __init__(self, code, discount, user_tier=None, is_admin=False):
        self.code = code
        self.discount = discount
        self.user_tier = user_tier
        self.is_admin = is_admin


def validate_cart(cart):
    return len(cart.items) > 0


def apply_discount(cart, discount_code):
    if discount_code.is_admin and not cart.user.is_admin:
        return None
    if discount_code.user_tier and cart.user.user_tier != discount_code.user_tier:
        return None
    total = sum(item.price for item in cart.items)
    return total - (total * discount_code.discount)


def calculate_tax(amount, tax_rate=0.07):
    return amount + (amount * tax_rate)


def process_payment(amount):
    return amount


def create_order_record(cart, amount):
    return {'user': cart.user.username, 'amount': amount}


def checkout_process(cart, discount_code):
    if not validate_cart(cart):
        return 'Invalid cart'
    discounted_price = apply_discount(cart, discount_code)
    if discounted_price is None:
        return 'Invalid discount code'
    total_with_tax = calculate_tax(discounted_price)
    payment = process_payment(total_with_tax)
    order = create_order_record(cart, payment)
    return order